/**
 * Magic-link 风格的邮箱登录 provider（用 Credentials 实现，零外部依赖）。
 * 接收邮箱 + 一次性验证码，校验通过即登录。加入 authConfig.providers[]。
 * 注：生产需接真实邮件发送 + 验证码存储；此处为可编译的骨架（验证码校验留 TODO）。
 */
export const magicLinkProvider = CredentialsProvider({
  id: "magic-link",
  name: "邮箱登录",
  credentials: {
    email: { label: "邮箱", type: "email" },
    code: { label: "验证码", type: "text" },
  },
  authorize(credentials) {
    const email = credentials?.email;
    const code = credentials?.code;
    if (typeof email !== "string" || typeof code !== "string") {
      return null;
    }
    // TODO: 校验 code 与发送记录是否匹配（接邮件服务后实现）
    if (code.length < 4) {
      return null;
    }
    return { id: email, email, name: email.split("@")[0] ?? email };
  },
});

"use client";

interface MarkdownViewProps {
  source: string;
}

function escapeHtml(text: string): string {
  return text.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

function renderInline(text: string): string {
  let out = escapeHtml(text);
  out = out.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>");
  out = out.replace(/\*([^*]+)\*/g, "<em>$1</em>");
  out = out.replace(/`([^`]+)`/g, "<code>$1</code>");
  out = out.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
  return out;
}

/**
 * 支持 ``` 代码块（fenced code）的 markdown 渲染。保持 MarkdownView({source}) 契约。
 * 代码块内不做 inline 解析、原样转义。零依赖。
 */
function toHtml(markdown: string): string {
  const lines = markdown.split("\n");
  const html: string[] = [];
  let i = 0;
  while (i < lines.length) {
    const line = lines[i] ?? "";
    if (/^```/.test(line)) {
      const code: string[] = [];
      i++;
      while (i < lines.length && !/^```/.test(lines[i] ?? "")) {
        code.push(escapeHtml(lines[i] ?? ""));
        i++;
      }
      i++; // 跳过结束 ```
      html.push(`<pre><code>${code.join("\n")}</code></pre>`);
      continue;
    }
    const heading = /^(#{1,6})\s+(.*)$/.exec(line);
    if (heading) {
      const level = (heading[1] ?? "").length;
      html.push(`<h${level}>${renderInline(heading[2] ?? "")}</h${level}>`);
      i++;
      continue;
    }
    if (line.trim()) html.push(`<p>${renderInline(line)}</p>`);
    i++;
  }
  return html.join("");
}

export function MarkdownView({ source }: MarkdownViewProps) {
  return <div className="prose" dangerouslySetInnerHTML={{ __html: toHtml(source) }} />;
}

