interface MarkdownViewProps {
  source: string;
}

function escapeHtml(text: string): string {
  return text.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

/**
 * 极简 markdown 渲染：只处理标题与段落，不解析 inline 标记。保持 MarkdownView({source}) 契约。
 * 最轻量、最安全（不渲染任意 inline HTML），适合可信度低或只需基础排版的场景。零依赖。
 */
function toHtml(markdown: string): string {
  const html: string[] = [];
  for (const line of markdown.split("\n")) {
    const heading = /^(#{1,6})\s+(.*)$/.exec(line);
    if (heading) {
      const level = (heading[1] ?? "").length;
      html.push(`<h${level}>${escapeHtml(heading[2] ?? "")}</h${level}>`);
    } else if (line.trim()) {
      html.push(`<p>${escapeHtml(line)}</p>`);
    }
  }
  return html.join("");
}

export function MarkdownView({ source }: MarkdownViewProps) {
  return <div className="prose" dangerouslySetInnerHTML={{ __html: toHtml(source) }} />;
}

"use client";

interface MarkdownViewProps {
  source: string;
}

function escapeHtml(text: string): string {
  return text.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

function renderInline(text: string): string {
  let out = escapeHtml(text);
  out = out.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>");
  out = out.replace(/\*([^*]+)\*/g, "<em>$1</em>");
  out = out.replace(/`([^`]+)`/g, "<code>$1</code>");
  out = out.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
  return out;
}

/**
 * 支持 GFM 表格的 markdown 渲染。保持 MarkdownView({source}) 契约。
 * 在基础渲染上额外解析 | a | b | 形式的表格。零依赖正则实现。
 */
function toHtml(markdown: string): string {
  const lines = markdown.split("\n");
  const html: string[] = [];
  let i = 0;
  while (i < lines.length) {
    const line = lines[i] ?? "";
    // 表格：当前行和下一行是 |---| 分隔
    const next = lines[i + 1] ?? "";
    if (/^\s*\|.*\|\s*$/.test(line) && /^\s*\|[\s:|-]+\|\s*$/.test(next)) {
      const parseRow = (r: string): string[] =>
        r.trim().replace(/^\||\|$/g, "").split("|").map((c) => c.trim());
      const headers = parseRow(line);
      html.push("<table><thead><tr>");
      for (const h of headers) html.push(`<th>${renderInline(h)}</th>`);
      html.push("</tr></thead><tbody>");
      i += 2;
      while (i < lines.length && /^\s*\|.*\|\s*$/.test(lines[i] ?? "")) {
        const cells = parseRow(lines[i] ?? "");
        html.push("<tr>");
        for (const cell of cells) html.push(`<td>${renderInline(cell)}</td>`);
        html.push("</tr>");
        i++;
      }
      html.push("</tbody></table>");
      continue;
    }
    const heading = /^(#{1,6})\s+(.*)$/.exec(line);
    if (heading) {
      const level = (heading[1] ?? "").length;
      html.push(`<h${level}>${renderInline(heading[2] ?? "")}</h${level}>`);
      i++;
      continue;
    }
    if (line.trim()) html.push(`<p>${renderInline(line)}</p>`);
    i++;
  }
  return html.join("");
}

export function MarkdownView({ source }: MarkdownViewProps) {
  return <div className="prose" dangerouslySetInnerHTML={{ __html: toHtml(source) }} />;
}

type ParsedRecord = {
  name: string;
  description?: string;
};

function splitCsvLine(line: string): string[] {
  const fields: string[] = [];
  let cur = "";
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (inQuotes) {
      if (ch === '"') {
        if (line[i + 1] === '"') {
          cur += '"';
          i++;
        } else {
          inQuotes = false;
        }
      } else {
        cur += ch;
      }
    } else if (ch === '"') {
      inQuotes = true;
    } else if (ch === ",") {
      fields.push(cur);
      cur = "";
    } else {
      cur += ch;
    }
  }
  fields.push(cur);
  return fields;
}

export function parseContactsCsv(csv: string): ParsedRecord[] {
  const lines = csv.replace(/\r\n/g, "\n").replace(/\r/g, "\n").split("\n");
  const records: ParsedRecord[] = [];
  let headerCols: string[] | null = null;

  for (const rawLine of lines) {
    const line = rawLine.trim();
    if (line === "") continue;
    const fields = splitCsvLine(line);
    if (headerCols === null) {
      headerCols = fields.map((f) => f.trim().toLowerCase());
      continue;
    }
    const row: Record<string, string> = {};
    headerCols.forEach((col, idx) => {
      row[col] = (fields[idx] ?? "").trim();
    });
    const name = row.name ?? row.姓名 ?? fields[0] ?? "";
    if (name === "") continue;
    records.push({
      name,
      description: row.description ?? row.备注 ?? undefined,
    });
  }
  return records;
}

type ParsedRow = Record<string, string>;

function splitCsvLine(line: string): string[] {
