/**
 * 通用 CSV 解析：首行作表头，每行映射为 Record<string,string>。
 * 不绑定具体实体（对比 csv-contacts-import 的固定 name/description）。零依赖。
 */
export function parseCsv(csv: string): ParsedRow[] {
  const lines = csv.split(/\r?\n/).filter((l) => l.trim() !== "");
  if (lines.length === 0) return [];
  const headers = splitCsvLine(lines[0] ?? "");
  const rows: ParsedRow[] = [];
  for (let i = 1; i < lines.length; i++) {
    const cells = splitCsvLine(lines[i] ?? "");
    const row: ParsedRow = {};
    headers.forEach((h, idx) => {
      row[h] = cells[idx] ?? "";
    });
    rows.push(row);
  }
  return rows;
}

type ParsedRow = Record<string, string>;

/**
 * JSON 数组批量导入：解析 JSON 数组，每项规整为 Record<string,string>（值转字符串）。
 * 适合从 API/导出的 JSON 批量导入。零依赖。非数组或非法 JSON 返回空数组。
 */
export function parseJsonImport(json: string): ParsedRow[] {
  let data: unknown;
  try {
    data = JSON.parse(json);
  } catch {
    return [];
  }
  if (!Array.isArray(data)) return [];
  const rows: ParsedRow[] = [];
  for (const item of data) {
    if (item === null || typeof item !== "object") continue;
    const row: ParsedRow = {};
    for (const [k, v] of Object.entries(item as Record<string, unknown>)) {
      row[k] = v === null || v === undefined ? "" : String(v);
    }
    rows.push(row);
  }
  return rows;
}

type ParsedRow = Record<string, string>;

/**
 * TSV（制表符分隔）批量导入：首行表头，按 \t 切列。
 * 适合从 Excel/Sheets 复制粘贴的数据（TSV 比 CSV 少引号转义问题）。零依赖。
 */
export function parseTsvImport(tsv: string): ParsedRow[] {
  const lines = tsv.split(/\r?\n/).filter((l) => l.trim() !== "");
  if (lines.length === 0) return [];
  const headers = (lines[0] ?? "").split("\t");
  const rows: ParsedRow[] = [];
  for (let i = 1; i < lines.length; i++) {
    const cells = (lines[i] ?? "").split("\t");
    const row: ParsedRow = {};
    headers.forEach((h, idx) => {
      row[h.trim()] = (cells[idx] ?? "").trim();
    });
    rows.push(row);
  }
  return rows;
}

import { z } from "zod";

import { createTRPCRouter, protectedProcedure } from "~/server/api/trpc";
import { db } from "~/server/db";

type CrudModel = {
  findMany: (args: { orderBy: { createdAt: "desc" } }) => Promise<unknown>;
  findUnique: (args: { where: { id: string } }) => Promise<unknown>;
  create: (args: {
    data: { name: string; description?: string | undefined };
  }) => Promise<unknown>;
  update: (args: {
    where: { id: string };
    data: { name?: string | undefined; description?: string | undefined };
  }) => Promise<unknown>;
  delete: (args: { where: { id: string } }) => Promise<unknown>;
};

const createInput = z.object({
  name: z.string().min(1),
  description: z.string().min(1).optional(),
});

const updateInput = z.object({
  id: z.string(),
  name: z.string().min(1).optional(),
  description: z.string().min(1).optional(),
});

export const createCrudRouter = (model: CrudModel) =>
  createTRPCRouter({
    list: protectedProcedure.query(async () => {
      return model.findMany({
        orderBy: { createdAt: "desc" },
      });
    }),

    get: protectedProcedure
      .input(z.object({ id: z.string() }))
      .query(async ({ input }) => {
        return model.findUnique({
          where: { id: input.id },
        });
      }),

    create: protectedProcedure
      .input(createInput)
      .mutation(async ({ input }) => {
        return model.create({
          data: {
            name: input.name,
            description: input.description,
          },
        });
      }),

    update: protectedProcedure
      .input(updateInput)
      .mutation(async ({ input }) => {
        const { id, ...data } = input;

        return model.update({
          where: { id },
          data,
        });
      }),

    delete: protectedProcedure
      .input(z.object({ id: z.string() }))
      .mutation(async ({ input }) => {
        return model.delete({
          where: { id: input.id },
        });
      }),
  });

// 用 db 单例（模块级，非请求期 ctx）绑定具体 model，导出成品 router。
