/**
 * 本地 data-URL 上传：把 File 读成 base64 data URL，返回可直接用作 src 的 URL。
 * 零依赖、零后端，适合 MVP/预览（图片头像等小文件）。不持久化、不适合大文件。
 */
export async function uploadFile(file: File): Promise<{ url: string }> {
  const dataUrl = await new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(typeof reader.result === "string" ? reader.result : "");
    reader.onerror = () => reject(new Error("读取文件失败"));
    reader.readAsDataURL(file);
  });
  return { url: dataUrl };
}

/**
 * 预签名 URL 上传：把文件 PUT 到调用方提供的预签名 URL（S3/R2/OSS 常见模式），
 * 返回去掉 query 的可访问 URL。零依赖（浏览器原生 fetch）。
 * 需调用方先拿到 presignedUrl（由后端签发）；本函数只负责上传动作。
 */
export async function uploadFile(
  file: File,
  presignedUrl: string,
): Promise<{ url: string }> {
  const resp = await fetch(presignedUrl, {
    method: "PUT",
    body: file,
    headers: { "Content-Type": file.type || "application/octet-stream" },
  });
  if (!resp.ok) {
    throw new Error(`上传失败 HTTP ${resp.status}`);
  }
  const url = presignedUrl.split("?")[0] ?? presignedUrl;
  return { url };
}

type ExportRow = Record<string, string | number | boolean | null | undefined>;

function escapeCell(value: string | number | boolean | null | undefined): string {
  const str = value === null || value === undefined ? "" : String(value);
  if (/[",\n\r]/.test(str)) {
    return `"${str.replace(/"/g, '""')}"`;
  }
  return str;
}

/**
 * 复制到剪贴板的导出。保持 (rows, columns?) 契约，产出 CSV 文本，
 * copyToClipboard 用浏览器原生 navigator.clipboard 写入。零依赖。
 */
export function rowsToClipboardText(rows: ExportRow[], columns?: string[]): string {
  const first = rows[0];
  if (!first) return "";
  const cols = columns ?? Object.keys(first);
  const header = cols.map(escapeCell).join(",");
  const body = rows
    .map((row) => cols.map((c) => escapeCell(row[c])).join(","))
    .join("\n");
  return `${header}\n${body}`;
}

export async function copyToClipboard(rows: ExportRow[], columns?: string[]): Promise<boolean> {
  const text = rowsToClipboardText(rows, columns);
  try {
